import React from "react";
import axios from "axios";
import Volu from './../Volu/Volu';;

// import List from './components/itemList.js'

class Items extends React.Component{
    state = {
        items:[]
    };


     handleSubmit(e){
    axios.get("https://localhost:5000/Volunteering").then(result => {
    const finalResult = result.data;
    console.log(finalResult) // array of object
    this.setState({items:finalResult})
  }).catch(err => {
    console.log("Error",err);
  });
   }

   render(){
    return(
        <div>
        <button onClick = {this.handleSubmit.bind(this)}></button>
        <Volu/>
        <ul>
          {this.state.items.map((element,index)=>(
          <li key={index}>
            {element.Category}....{element.Description}.....{element.address}.....{element.company_id}

          </li>))}
        </ul>
        </div>
    );
    };
}
export default Items;
